import email
from email.header import decode_header
import re

def poll(last_cursor: str | None = None) -> dict:
    """
    轮询 Gmail 收件箱，返回新邮件事件。

    Args:
        last_cursor: 上一次轮询时最新邮件 UID，首次轮询为 None

    Returns:
        dict: {"events": [...], "next_cursor": "..."}
    """
    # ===== 配置区：请填写你的 Gmail 凭据 =====
    EMAIL_ACCOUNT = "your_email@gmail.com"
    APP_PASSWORD = "your_app_password"  # 需使用 Gmail 应用专用密码

    events = []

    try:
        # 连接 Gmail IMAP 服务器
        mail = imaplib.IMAP4_SSL("imap.gmail.com")
        mail.login(EMAIL_ACCOUNT, APP_PASSWORD)
        mail.select("INBOX")

        # 查询收件箱邮件 UID
        if last_cursor:
            # 只获取比上次光标更新的邮件
            status, uid_data = mail.uid("SEARCH", None, f"UID {last_cursor}:*")
        else:
            # 首次轮询，获取最近 10 封邮件
            status, uid_data = mail.uid("SEARCH", None, "ALL")

        if status != "OK" or not uid_data[0]:
            mail.logout()
            return {"events": [], "next_cursor": last_cursor}

        # 解析 UID 列表，升序排列
        uids = uid_data[0].split()
        if not uids:
            mail.logout()
            return {"events": [], "next_cursor": last_cursor}

        # 仅处理新增的邮件（排除 last_cursor 本身）
        new_uids = []
        for uid in uids:
            uid_str = uid.decode()
            if last_cursor is None or int(uid_str) > int(last_cursor):
                new_uids.append(uid_str)

        if not new_uids:
            mail.logout()
            return {"events": [], "next_cursor": last_cursor or uids[-1].decode()}

        # 获取每封新邮件的详情
        for uid_str in new_uids:
            status, msg_data = mail.uid("FETCH", uid_str, "(RFC822)")
            if status != "OK":
                continue

            raw_email = msg_data[0][1]
            msg = email.message_from_bytes(raw_email)

            # 解析发件人
            from_header = msg.get("From", "未知")
            # 解析主题
            subject_header = msg.get("Subject", "无主题")
            subject, encoding = decode_header(subject_header)[0]
            if isinstance(subject, bytes):
                subject = subject.decode(encoding if encoding else "utf-8", errors="replace")

            # 解析日期
            date_str = msg.get("Date", "")

            events.append({
                "type": "new_email",
                "data": {
                    "uid": uid_str,
                    "from": from_header,
                    "subject": subject,
                    "date": date_str,
                    "preview": _get_preview(msg),
                }
            })

        # 更新光标为最新的 UID
        next_cursor = uids[-1].decode()
        mail.logout()

        return {"events": events, "next_cursor": next_cursor}

    except Exception as e:
        return {"events": [{"type": "error", "data": {"message": str(e)}}], "next_cursor": last_cursor}


def _get_preview(msg) -> str:
    """从邮件中提取纯文本预览（前 200 字符）"""
    if msg.is_multipart():
        for part in msg.walk():
            content_type = part.get_content_type()
            if content_type == "text/plain":
                try:
                    payload = part.get_payload(decode=True)
                    charset = part.get_content_charset() or "utf-8"
                    text = payload.decode(charset, errors="replace")
                    cleaned = re.sub(r"\s+", " ", text).strip()
                    return cleaned[:200] + "..." if len(cleaned) > 200 else cleaned
                except:
                    continue
    else:
        try:
            payload = msg.get_payload(decode=True)
            charset = msg.get_content_charset() or "utf-8"
            text = payload.decode(charset, errors="replace")
            cleaned = re.sub(r"\s+", " ", text).strip()
            return cleaned[:200] + "..." if len(cleaned) > 200 else cleaned
        except:
            pass
    return ""
"}

