                    "date": headers.get("Date", ""),
                    "timestamp": internal_date,
                    "snippet": msg_detail.get("snippet", "")
                }
            })

            # 更新 latest_id 为最新邮件的时间戳
            if latest_id is None or internal_date > int(latest_id):
                latest_id = str(internal_date)

        # 可选：标记为已读（注释掉以保持原始行为）
        # for msg in messages:
        #     service.users().messages().modify(
        #         userId="me", id=msg["id"], body={"removeLabelIds": ["UNREAD"]}
        #     ).execute()

        return {
            "events": events,
            "next_cursor": latest_id or str(int(datetime.now(timezone.utc).timestamp()))
