from datetime import datetime, timezone

def poll(last_cursor):
    """
    Poll Gmail inbox for new emails.

    Args:
        last_cursor: The last processed email UID (string), or None on first run.

    Returns:
        dict with:
          - events: list of event dicts, each containing email metadata
          - next_cursor: the UID of the latest processed email
    """
