    IMAP_SERVER = os.getenv("GMAIL_IMAP_SERVER", "imap.gmail.com")
    USERNAME = os.getenv("GMAIL_USERNAME", "")
    PASSWORD = os.getenv("GMAIL_APP_PASSWORD", "")  # Use App Password for Gmail

