        if not uids:
            mail.logout()
            return {
                "events": [],
                "next_cursor": last_cursor or "0"
            }

        events = []
        last_uid = last_cursor or "0"

        for uid in uids:
            uid_str = uid.decode()
            # Only process emails newer than our last cursor
            if int(uid_str) <= int(last_uid):
