IMAP_PORT = 993
# 建议使用应用专用密码，而非主密码
# 也可通过环境变量或 handler 注入凭据
GMAIL_ACCOUNT = "your_email@gmail.com"
GMAIL_APP_PASSWORD = "your_app_password"
# ===================

def _decode_mime_header(header_value):
    """解码邮件标题"""
    if header_value is None:
        return ""
    decoded_parts = decode_header(header_value)
    result = []
    for part, charset in decoded_parts:
        if isinstance(part, bytes):
            try:
                result.append(part.decode(charset or "utf-8", errors="replace"))
            except (LookupError, UnicodeDecodeError):
                result.append(part.decode("utf-8", errors="replace"))
        else:
            result.append(part)
    return " ".join(result)

def poll(last_cursor: str = None) -> dict:
    """
    轮询 Gmail 收件箱，返回新邮件事件列表。

    Args:
        last_cursor: 上次处理的最新邮件 UID (RFC822.SIZE)，用于增量检查

    Returns:
        dict: {
            "events": [...],
            "next_cursor": str  # 本次最新邮件 UID
        }
    """
    try:
        # 连接到 Gmail IMAP
        mail = imaplib.IMAP4_SSL(IMAP_SERVER, IMAP_PORT)
        mail.login(GMAIL_ACCOUNT, GMAIL_APP_PASSWORD)
        mail.select("INBOX")

        # 搜索邮件
        if last_cursor:
            # 只搜索比上次 cursor 更新的邮件
            search_criteria = f"UID {int(last_cursor) + 1}:*"
        else:
            # 首次运行：只取最近 5 封
            search_criteria = "ALL"

        status, messages = mail.search(None, search_criteria)
        if status != "OK" or not messages[0]:
            return {"events": [], "next_cursor": last_cursor or "0"}

        uid_list = messages[0].split()

        if not last_cursor and len(uid_list) > 5:
            # 首次只处理最近 5 封，避免事件风暴
            uid_list = uid_list[-5:]

        events = []
        latest_uid = last_cursor or "0"

        for uid_bytes in uid_list:
            uid = uid_bytes.decode()
            if int(uid) > int(latest_uid):
                latest_uid = uid

            # 获取邮件内容
            status, msg_data = mail.fetch(uid_bytes, "(RFC822)")
            if status != "OK":
                continue

            raw_email = msg_data[0][1]
            msg = email.message_from_bytes(raw_email)

            # 提取关键信息
            subject = _decode_mime_header(msg["Subject"])
            sender = _decode_mime_header(msg["From"])
            date_str = msg["Date"]

            try:
                received_at = parsedate_to_datetime(date_str).isoformat() if date_str else datetime.now(timezone.utc).isoformat()
            except Exception:
                received_at = datetime.now(timezone.utc).isoformat()

            # 获取邮件正文预览
            body_preview = ""
            if msg.is_multipart():
                for part in msg.walk():
                    if part.get_content_type() == "text/plain":
                        body_preview = part.get_payload(decode=True)
                        if body_preview:
                            body_preview = body_preview.decode("utf-8", errors="replace")[:200]
                        break
            else:
                body_preview = msg.get_payload(decode=True)
                if body_preview:
                    body_preview = body_preview.decode("utf-8", errors="replace")[:200]

            events.append({
                "type": "new_email",
                "data": {
                    "uid": uid,
                    "subject": subject,
                    "from": sender,
                    "received_at": received_at,
                    "preview": body_preview,
                    "account": GMAIL_ACCOUNT
                }
            })

        mail.logout()

        return {
            "events": events,
            "next_cursor": str(latest_uid)
        }

    except imaplib.IMAP4.error as e:
        return {
            "events": [{
                "type": "error",
                "data": {
                    "message": f"Gmail IMAP error: {str(e)}",
                    "timestamp": datetime.now(timezone.utc).isoformat()
                }
            }],
            "next_cursor": last_cursor or "0"
        }
    except Exception as e:
        return {
            "events": [{
                "type": "error",
                "data": {
                    "message": f"Unexpected error: {str(e)}",
                    "timestamp": datetime.now(timezone.utc).isoformat()
                }
            }],
            "next_cursor": last_cursor or "0"
        }
"}
